      }
    },
    // async getGacetaAll() {
    //   try {
    //     let res = await this.axios.get(
    //       "/api/gacetaunivAll/" + process.env.VUE_APP_ID_INSTITUCION
    //     );
    //     this.Gaceta = [];
    //     res.data.forEach((gaceta) => {
    //       if (gaceta.gaceta_estado == "1") {
    //         this.Gaceta.push(gaceta);
    //       }
    //     });
    //     this.pager = this.Gaceta.length / this.NUM_RESULTS;
    //     if (this.pager - Math.trunc(this.pager) > 0) {
    //       this.pager = Math.trunc(this.pager) + 1;
    //     }
    //     this.$store.commit("loading");
    //   } catch (error) {
    //     console.log(error);
    //   }
    // },
    async getEventos() {
      try {
        let res = await this.axios.get(
          "/api/eventoAll/" + process.env.VUE_APP_ID_INSTITUCION
        );
        this.Event = res.data;
      } catch (error) {
        console.log(error);
      }
    },
    async getVideos() {
      try {
        let res = await this.axios.get(
          "/api/VideosAll/" + process.env.VUE_APP_ID_INSTITUCION
        );
        this.Vid = res.data;
        this.$store.commit("loading");
      } catch (error) {
        console.log(error);
      }
    },
    async setImage(id, img) {
      try {
        await document
          .querySelector("." + id)
          .setAttribute("style", 'background-image: url("' + img + '");');
      } catch (error) {
        console.log(error);
      }
    },
    contarConv(tipo) {
      if (tipo && this.Conv) {
        let count = 0;
        this.Conv.forEach((conv) => {
          if (conv.tipo_conv_comun.tipo_conv_comun_titulo == tipo) {
            count++;
          }
        });
        return count;
      }
    },
    contarCur(tipo) {
      if (tipo && this.Cur) {
        let count = 0;
        this.Cur.forEach((cur) => {
          if (cur.tipo_curso_otro.tipo_conv_curso_nombre == tipo) {
            count++;
          }
        });
        return count;
      }
    },
  },
