<template>
  <!-- ==============================================
    ** Inner Banner **
    =================================================== -->
  <div class="inner-banner blog">
    <div class="container">
      <div class="row">
        <div class="col-sm-12">
          <div class="content">
            <h1>Sobre nosotros</h1>
          </div>

          <h4>
                  <router-link to="/">INICIO</router-link>
                </h4>
              
        </div>
      </div>
    </div>
  </div>


  <div class="container blog-wrapper padding-lg">
    <div class="row">
      <!-- Start Left Column -->
      <div class="col-sm-8 blog-left">
        <p class="content left-aligned" v-html="Institucion.institucion_sobre_ins"></p>
      </div>
      <!-- End Left Column -->

      <!-- Start Right Column -->
      <div class="col-sm-4">
        <sidebar-custom></sidebar-custom>
      </div>
      <!-- End Right Column -->
    </div>
  </div>


  <!-- ==============================================
    ** Our Importance **
    =================================================== -->
  <section class="our-impotance padding-lg">
    <div class="container">
      <ul class="row ">
        <div class="col-sm-6 ">

          <h3>Visión</h3>
          <p class="left-aligned" v-html="Institucion.institucion_vision"></p>

        </div>
        <div class="col-sm-6 ">

          <h3>Misión</h3>
          <p class="left-aligned" v-html="Institucion.institucion_mision"></p>

        </div>
      </ul>
    </div>
  </section>

  <!-- ==============================================
    ** Browse Teacher **
    =================================================== -->
  <section class="browse-teacher grey-bg padding-lg">
    <div class="container">
      <h2><span>AUTORIDADES DE LA CARRERA DE {{ Institucion.institucion_nombre }}</span> Nuestras Autoridades</h2>
      <ul class="row browse-teachers-list clearfix">
        <li class="col-12 col-md-4" v-for="(autoridad, id_aut) of Institucion.autoridad" :key="id_aut" v-show="(pag - 1) * NUM_RESULTS <= id_aut && pag * NUM_RESULTS > id_aut
          ">
          <figure> <img :src="url_api +
            '/InstitucionUpea/Autoridad/' +
            autoridad.foto_autoridad
            " width="123" height="124" alt=""> </figure>
          <h3>{{ autoridad.nombre_autoridad }}</h3>
          <span class="designation">{{ autoridad.cargo_autoridad }}</span>
          <ul class="teachers-follow">
            <li v-if="autoridad.facebook_autoridad">
              <a :href="autoridad.facebook_autoridad" target="_blank">
                <i class="fa fa-facebook" aria-hidden="true"></i></a>
            </li>
            <li v-if="autoridad.twiter_autoridad">
              <a :href="autoridad.twiter_autoridad" target="_blank">
                <i class="fa fa-twitter" aria-hidden="true"></i></a>
            </li>
            <li v-if="autoridad.celular_autoridad">
              <a :href="'https://wa.me/+' + autoridad.celular_autoridad" target="_blank">
                <i class="fa fa-whatsapp" aria-hidden="true"></i></a>
            </li>
          </ul>
        </li>
      </ul>
    </div>
  </section>
</template>


<script>
import { mapState } from "vuex";
import SidebarCustom from "@/components/SidebarCustom.vue";

export default {
  name: "AboutView",
  data() {
    return {
      Conv: [],
      Cur: [],
      Serv: [],
      Ofer: [],

      // NUM_RESULTS: 3,
      // pag: 1,
      // pager: 0,

      tipo: "",
      Convocatorias: [],
      search: "",
      searchGet: false,
      searchValues: [],

      NUM_RESULTS: 4,
      pag: 1,
      pager: 0,
    };
  },
  components: {
    SidebarCustom,
  },
  computed: {
    ...mapState(["Institucion", "url_api", "getter"]),
  },
  methods: {
    async getConvocatoriasAll() {
      try {
        let res = await this.axios.get(
          "/api/convocatoriasAll/" + process.env.VUE_APP_ID_CARRERA
        );
        this.Conv = res.data;
        this.pager = this.Institucion.autoridad.length / this.NUM_RESULTS;
        if (this.pager - Math.trunc(this.pager) > 0) {
          this.pager = Math.trunc(this.pager) + 1;
        }
      } catch (error) {
        console.log(error);
      }
    },
    async getCursosAll() {
      try {
        let res = await this.axios.get(
          "/api/cursosAll/" + process.env.VUE_APP_ID_CARRERA
        );
        this.Cur = res.data;
      } catch (error) {
        console.log(error);
      }
    },
    async getServiciosAll() {
      try {
        let res = await this.axios.get(
          "/api/ServicioAll/" + process.env.VUE_APP_ID_CARRERA
        );
        this.Serv = res.data;
      } catch (error) {
        console.log(error);
      }
    },
    async getOfertasAll() {
      try {
        let res = await this.axios.get(
          "/api/OfertasAcademicasAll/" + process.env.VUE_APP_ID_CARRERA
        );
        this.Ofer = res.data;
        this.$store.commit("loading");
      } catch (error) {
        console.log(error);
      }
    },
    async getTipoConv(tipo_conv) {
      try {
        let res = await this.axios.get("/api/Tipoconvocatorias/" + tipo_conv);
        this.tipo = res.data.Descripcion.tipo_conv_comun_titulo;
        this.getConvocatorias();
      } catch (error) {
        console.log(error);
      }
    },
    async getConvocatorias() {
      try {
        let res = await this.axios.get(
          "/api/convocatoriasAll/" + process.env.VUE_APP_ID_CARRERA
        );
        this.Convocatorias = [];
        res.data.forEach((cca) => {
          if (
            cca.con_estado == "1" &&
            cca.tipo_conv_comun.tipo_conv_comun_titulo == this.tipo
          ) {
            this.Convocatorias.push(cca);
          }
        });
        this.pager = this.Convocatorias.length / this.NUM_RESULTS;
        if (this.pager - Math.trunc(this.pager) > 0) {
          this.pager = Math.trunc(this.pager) + 1;
        }
        this.$store.commit("loading");
      } catch (error) {
        console.log(error);
      }
    },
    clickBack() {
      this.$store.commit("clickLink");
      this.$router.go(-1);
    },
    dmy(fecha) {
      const meses = [
        "enero",
        "febrero",
        "marzo",
        "abril",
        "mayo",
        "junio",
        "julio",
        "agosto",
        "septiembre",
        "octubre",
        "noviembre",
        "diciembre",
      ];
      let fechaCadena = fecha.substr(0, 10);
      let fechaArray = fechaCadena.split("-");
      return (
        fechaArray[2] +
        " de " +
        meses[fechaArray[1] - 1] +
        " de " +
        fechaArray[0]
      );
    },
    buscar() {
      if (this.search != "") {
        this.searchGet = true;

        this.searchValues = [];
        this.Convocatorias.forEach((conv) => {
          if (
            conv.con_titulo.toUpperCase().includes(this.search.toUpperCase())
          ) {
            this.searchValues.push(conv);
          }
        });
      } else {
        this.searchGet = false;
      }
    },
  },
  mounted() {
    this.$store.commit("loadOn");
    // this.getTipoConv(this.$route.params.tipo_conv);
  },
  updated() {
    if (this.getter) {
      this.$store.commit("loadOn");
      // this.getTipoConv(this.$route.params.tipo_conv);
      this.$store.state.getter = false;
    }
  },
  created() {
    this.$store.commit("loadOn");
    // this.getTipoConv(this.$route.params.tipo_conv);

    this.getConvocatoriasAll();
    this.getCursosAll();
    this.getServiciosAll();
    this.getOfertasAll();
  },
};
</script>

<style scoped>
.centered-text {
  text-align: center;
  padding: 0 65px;
  /* Ajusta el espacio horizontal aquí */
}

.text-wrap {
  text-align: justify;
  padding: 0 70px;
}

p {
  margin-bottom: 5px;
}

.bg-overlay-img {
  background-image: url("@/assets/Fondo2.jpg");
}

.left-aligned {
  text-align: left;
}
</style>
